/// OPEN OUTPUT NEW-VERSION
fn new_version_open_output(state: &mut ProgramState) {
    let path = std::env::var("NEW_VERSION").unwrap_or("new_version.dat".to_string());
    match CobolFile::open_output(&path) {
        Ok(handle) => { state._fh_new_version = handle; state._fs_new_version = FileStatus::Success; }
        Err(_) => { state._fs_new_version = FileStatus::Error("35".to_string()); }
    }
}

/// READ NEW-VERSION
fn new_version_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_new_version.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(80);
            if _len > 0 { let _end = _len.min(0+75); state.new_statement = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 75 { let _end = _len.min(75+5); state.new_number = FixedString::from(String::from_utf8_lossy(&_bytes[75.._end])); }
            state._fs_new_version = FileStatus::Success;
        }
        Err(FileStatus::AtEnd) => {
            state._fs_new_version = FileStatus::AtEnd;
        }
        Err(e) => {
            state._fs_new_version = e.clone();
        }
    }
    Ok(())
}

/// WRITE to NEW-VERSION
fn new_version_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 80];
    { let _src = state.new_statement.as_bytes(); let _end = (0+75).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.new_number.as_bytes(); let _end = (75+5).min(_buf.len()); let _cl = _src.len().min(_end-75); _buf[75..75+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_new_version.write_record(&_buf) {
        Ok(()) => state._fs_new_version = FileStatus::Success,
        Err(e) => state._fs_new_version = e,
    }
}

/// CLOSE NEW-VERSION
fn new_version_close(state: &mut ProgramState) {
    match state._fh_new_version.close() {
        Ok(()) => state._fs_new_version = FileStatus::Success,
        Err(e) => state._fs_new_version = e,
    }
}

